        "+            if (!obj.Deserialize(data)) {",
        "+                return false;",
        "+            }",
        "+        }",
        "+        return true;",
        "+    }",
        "+};",
        "+",
        "+// ====================================================================",
        "+// 玩家输入",
        "+// ====================================================================",
        "+",
        "+/**",
        "+ * @brief 玩家输入结构体",
        "+ * ",
        "+ * 客户端将玩家的输入发送给服务器，服务器根据输入更新物理世界。",
