        "-enum class PhysicsObjectType : uint8_t {",
        "-    PLAYER = 0,     ///< 玩家控制的物体",
        "-    DYNAMIC = 1,    ///< 动态物理物体",
        "-    KINEMATIC = 2,  ///< 运动学物体",
        "-    STATIC = 3      ///< 静态物体",
